// Pre-hook: verifica env vars e filtra weekend
const now = new Date();
const dayOfWeek = now.getDay();
const startedAt = now.toISOString();

const missingVars = [];
if (!$env.TELEGRAM_BOT_TOKEN) missingVars.push('TELEGRAM_BOT_TOKEN');
if (!$env.TELEGRAM_CHAT_ID) missingVars.push('TELEGRAM_CHAT_ID');
if (missingVars.length > 0) {
  throw new Error('Pre-hook FAIL — env vars mancanti: ' + missingVars.join(', '));
}

// Questo workflow gira ogni lunedì — se triggerato manualmente in weekend va bene
return [{ json: { startedAt, workflow: 'linkedin-detection-monitor', ok: true } }];

// Analizza le risposte e costruisce il report di intelligence
const startedAt = $('Pre-hook: valida env').first().json.startedAt;
const searchData = $('Cerca: LinkedIn detection news 2026').first().json;
const safetyData = $('Fetch: Safety guide aggiornata').first().json;

// Estrai snippets rilevanti (testo grezzo semplificato)
const now = new Date().toISOString();

const report = {
  checkDate: now.split('T')[0],
  sources_checked: 2,
  topics_monitored: [
    'LinkedIn bot detection algorithms',
    'Behavioral biometrics detection',
    'Safe action limits 2026',
    'IP/VPN detection updates',
    'New TOS violations'
  ],
  action_required: 'Rivedere manualmente le fonti e aggiornare /antiban-review se ci sono novità',
