// Post-hook: logga completamento
const ts = new Date().toISOString();
const startedAt = $('Pre-hook: valida env').first().json.startedAt;
const durationMs = new Date(ts) - new Date(startedAt);
console.log(`[${ts}] linkedin-detection-monitor completato in ${durationMs}ms`);
return [{ json: { completedAt: ts, durationMs, status: 'ok' } }];
